@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="ToggleExpanded">
        <span>Change Password</span>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </button>

    @if (isExpanded)
    {
        <div class="password-form mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger" role="alert">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success" role="alert">@successMessage</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@isUpdating">
                @(isUpdating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isUpdating;

    private void ToggleExpanded() => isExpanded = !isExpanded;

    private async Task UpdatePassword()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }
        if (newPassword != confirmPassword)
        {
            errorMessage = "New passwords do not match.";
            return;
        }

        isUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            successMessage = "Password updated successfully.";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isUpdating = false;
        }
    }
}

@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

@if (isVisible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@DeviceName</strong>?</p>
                    <p class="text-muted">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public string SessionId { get; set; } = "";
    [Parameter] public string DeviceName { get; set; } = "";
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private bool isVisible;

    public void Show()
    {
        isVisible = true;
        StateHasChanged();
    }

    private async Task Confirm()
    {
        isVisible = false;
        await OnConfirm.InvokeAsync(SessionId);
    }

    private async Task Cancel()
    {
        isVisible = false;
        await OnCancel.InvokeAsync();
    }
}

@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="table-responsive">
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-sm btn-outline-danger"
                                    @onclick="() => RequestRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

<RevokeSessionDialog @ref="revokeDialog"
                     SessionId="@selectedSessionId"
                     DeviceName="@selectedDeviceName"
                     OnConfirm="HandleRevoke"
                     OnCancel="() => { }" />

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private RevokeSessionDialog revokeDialog = default!;
    private string selectedSessionId = "";
    private string selectedDeviceName = "";

    private void RequestRevoke(ActiveSession session)
    {
        selectedSessionId = session.Id;
        selectedDeviceName = session.Device;
        revokeDialog.Show();
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevoke.InvokeAsync(sessionId);
    }
}

@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Profile</h4>

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(avatarUrl))
                    {
                        <img src="@avatarUrl" alt="Avatar" class="rounded-circle" style="width:120px;height:120px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                             style="width:120px;height:120px;margin:0 auto;">
                            <span class="text-white fs-1">👤</span>
                        </div>
                    }
                </div>
                <div class="mb-2">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                </div>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show mt-2" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private string? statusMessage;
    private bool isSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !hasLocalEdits)
        {
            LoadFromProfile(Profile);
        }
    }

    private bool hasLocalEdits;

    private void LoadFromProfile(UserProfile p)
    {
        displayName = p.DisplayName;
        email = p.Email;
        avatarUrl = p.AvatarUrl;
        bio = p.Bio;
        hasLocalEdits = false;
    }

    private async Task SaveChanges()
    {
        isSaving = true;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            hasLocalEdits = false;
            statusMessage = "Profile saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            statusMessage = null;
        }
    }
}

@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Notifications</h4>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5>Muted Channels</h5>
    <div class="mb-4">
        @foreach (var channel in AvailableChannels)
        {
            var isMuted = mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Preferences")
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string> AvailableChannels { get; set; } = ["general", "announcements", "updates", "marketing", "alerts"];

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = [];
    private string? statusMessage;
    private bool isSaving;
    private bool initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !initialized)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = [.. Prefs.MutedChannels];
            initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, [.. mutedChannels]);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Security</h4>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <hr class="my-4" />

    <div class="d-flex justify-content-between align-items-center mb-3">
        <div>
            <h5 class="mb-1">Two-Factor Authentication</h5>
            <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                @(twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="twoFactor"
                   checked="@twoFactorEnabled"
                   @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
        </div>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted">Last password change: @Security.LastPasswordChange.Value.ToString("f")</p>
    }

    <hr class="my-4" />

    <h5>Active Sessions</h5>
    @if (Security is not null)
    {
        <ActiveSessionsTable Sessions="@Security.Sessions"
                             CurrentSessionId="@(Security.Sessions.Count > 0 ? Security.Sessions[0].Id : "")"
                             OnRevoke="HandleRevoke" />
    }

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @statusAlertClass alert-dismissible fade show mt-3" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private string? statusMessage;
    private string statusAlertClass = "alert-success";

    protected override void OnParametersSet()
    {
        if (Security is not null)
        {
            twoFactorEnabled = Security.TwoFactorEnabled;
        }
    }

    private async Task HandleChangePassword((string Current, string New) passwords)
    {
        await OnChangePassword.InvokeAsync(passwords);
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        statusMessage = "Session revoked successfully.";
        statusAlertClass = "alert-success";
    }
}

@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Appearance</h4>

    <div class="row">
