@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string> AvailableChannels { get; set; } = ["general", "announcements", "updates", "marketing", "alerts"];

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = [];
    private string? statusMessage;
    private bool isSaving;
    private bool initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !initialized)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            mutedChannels = [.. Prefs.MutedChannels];
            initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, [.. mutedChannels]);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Notification preferences saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

