@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

@if (isVisible)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@DeviceName</strong>?</p>
                    <p class="text-muted">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public string SessionId { get; set; } = "";
    [Parameter] public string DeviceName { get; set; } = "";
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private bool isVisible;

    public void Show()
    {
        isVisible = true;
        StateHasChanged();
    }

    private async Task Confirm()
    {
        isVisible = false;
        await OnConfirm.InvokeAsync(SessionId);
    }

    private async Task Cancel()
    {
        isVisible = false;
        await OnCancel.InvokeAsync();
    }
}

