@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="table-responsive">
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-sm btn-outline-danger"
                                    @onclick="() => RequestRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

<RevokeSessionDialog @ref="revokeDialog"
                     SessionId="@selectedSessionId"
                     DeviceName="@selectedDeviceName"
                     OnConfirm="HandleRevoke"
                     OnCancel="() => { }" />

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private RevokeSessionDialog revokeDialog = default!;
    private string selectedSessionId = "";
    private string selectedDeviceName = "";

    private void RequestRevoke(ActiveSession session)
    {
        selectedSessionId = session.Id;
        selectedDeviceName = session.Device;
        revokeDialog.Show();
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevoke.InvokeAsync(sessionId);
    }
}

