@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Security</h4>

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <hr class="my-4" />

    <div class="d-flex justify-content-between align-items-center mb-3">
        <div>
            <h5 class="mb-1">Two-Factor Authentication</h5>
            <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                @(twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="twoFactor"
                   checked="@twoFactorEnabled"
                   @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
        </div>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted">Last password change: @Security.LastPasswordChange.Value.ToString("f")</p>
    }

    <hr class="my-4" />

    <h5>Active Sessions</h5>
    @if (Security is not null)
    {
        <ActiveSessionsTable Sessions="@Security.Sessions"
                             CurrentSessionId="@(Security.Sessions.Count > 0 ? Security.Sessions[0].Id : "")"
                             OnRevoke="HandleRevoke" />
    }

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @statusAlertClass alert-dismissible fade show mt-3" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool twoFactorEnabled;
    private string? statusMessage;
    private string statusAlertClass = "alert-success";

    protected override void OnParametersSet()
    {
