@using sv_9c017a8b81d840868e3bd04fcdf59a73.Models
@namespace sv_9c017a8b81d840868e3bd04fcdf59a73.Components.Pages.Settings

<div class="settings-section">
    <h4>Appearance</h4>

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var t in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                               value="@t" checked="@(theme == t)"
                               @onchange="() => theme = t" />
                        <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var fs in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
                               value="@fs" checked="@(fontSize == fs)"
                               @onchange="() => fontSize = fs" />
                        <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>
        </div>

        <div class="col-md-6">
            <h5>Preview</h5>
            <div class="preview-area p-3 rounded border"
                 style="@PreviewStyle">
                <h6 style="@PreviewFontStyle">Sample Heading</h6>
                <p style="@PreviewFontStyle" class="@(compactMode ? "mb-1" : "mb-3")">
                    This is a preview of how your content will look with the selected appearance settings.
                </p>
                <div class="d-flex gap-2 @(compactMode ? "mb-1" : "mb-2")">
                    <span class="badge" style="@PreviewBadgeStyle">Badge</span>
                    <span class="badge" style="@PreviewBadgeStyle">Label</span>
                </div>
                <button class="btn btn-sm" style="@PreviewButtonStyle" disabled>
                    Sample Button
                </button>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary mt-3" @onclick="Save" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save")
    </button>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string theme = "System";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private string? statusMessage;
    private bool isSaving;
    private bool initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !initialized)
        {
            theme = Settings.Theme;
            fontSize = Settings.FontSize;
            language = Settings.Language;
            compactMode = Settings.CompactMode;
            initialized = true;
        }
    }

    private string PreviewStyle => theme switch
    {
        "Dark" => "background-color:#1e1e1e;color:#d4d4d4;",
        "Light" => "background-color:#ffffff;color:#212529;",
        _ => "background-color:#f8f9fa;color:#212529;"
    };

    private string PreviewFontStyle => fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.25rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewBadgeStyle => theme switch
    {
        "Dark" => "background-color:#0d6efd;color:#fff;",
        _ => "background-color:#0d6efd;color:#fff;"
    };

    private string PreviewButtonStyle => theme switch
    {
        "Dark" => "background-color:#0d6efd;color:#fff;border-color:#0d6efd;",
        _ => "background-color:#0d6efd;color:#fff;border-color:#0d6efd;"
    };

    private async Task Save()
    {
        isSaving = true;
        try
        {
            var updated = new AppearanceSettings(theme, fontSize, language, compactMode);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Appearance settings saved!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

