+    display: flex;
+    gap: 0;
+    min-height: 600px;
+}
+
+.settings-nav {
+    width: 220px;
+    flex-shrink: 0;
+    border-right: 1px solid #dee2e6;
+    background-color: #f8f9fa;
+}
+
+.settings-content {
+    flex: 1;
+    padding: 1.5rem 2rem;
+    min-width: 0;
+}
+
+/* Sidebar styles */
+::deep .settings-sidebar {
+    padding: 1rem 0;
+}
+
+::deep .sidebar-title {
+    padding: 0 1rem;
+    margin-bottom: 1rem;
+    font-weight: 600;
+    color: #495057;
+    text-transform: uppercase;
+    font-size: 0.75rem;
+    letter-spacing: 0.05em;
+}
+
+::deep .settings-sidebar .nav-link {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    padding: 0.6rem 1rem;
+    color: #495057;
+    border: none;
+    background: none;
+    width: 100%;
+    text-align: left;
+    font-size: 0.95rem;
+    border-left: 3px solid transparent;
+    transition: all 0.15s ease;
+    cursor: pointer;
+}
+
+::deep .settings-sidebar .nav-link:hover {
+    background-color: #e9ecef;
+    color: #212529;
+}
+
+::deep .settings-sidebar .nav-link.active {
+    background-color: #e7f1ff;
+    color: #0d6efd;
+    border-left-color: #0d6efd;
+    font-weight: 500;
+}
+
+::deep .section-icon {
+    font-size: 1.1rem;
+}
+
+/* Section styles */
+::deep .settings-section {
+    max-width: 800px;
+}
+
+::deep .settings-section h4 {
+    margin-bottom: 1.5rem;
+    padding-bottom: 0.75rem;
+    border-bottom: 1px solid #dee2e6;
+}
+
+/* Preview area */
+::deep .preview-area {
+    min-height: 150px;
+    transition: all 0.2s ease;
+}
+
+/* Password panel */
+::deep .change-password-panel {
+    max-width: 500px;
+}
+
+::deep .password-form {
+    padding: 1rem;
+    background-color: #f8f9fa;
+    border: 1px solid #dee2e6;
+    border-radius: 0.375rem;
+}
+
+/* Avatar */
+::deep .avatar-frame {
+    display: flex;
+    justify-content: center;
+}
+
+/* Modal overlay */
+::deep .modal-backdrop {
+    z-index: 1040;
+}
+
+::deep .modal {
+    z-index: 1050;
+}
+
+@media (max-width: 768px) {
+    .settings-dashboard {
+        flex-direction: column;
+    }
+
+    .settings-nav {
+        width: 100%;
+        border-right: none;
+        border-bottom: 1px solid #dee2e6;
+    }
+
+    ::deep .settings-sidebar .nav {
+        flex-direction: row !important;
+        overflow-x: auto;
+    }
+
+    ::deep .settings-sidebar .nav-link {
+        border-left: none;
+        border-bottom: 3px solid transparent;
+        white-space: nowrap;
+    }
+
+    ::deep .settings-sidebar .nav-link.active {
+        border-left-color: transparent;
+        border-bottom-color: #0d6efd;
+    }
+}
+
